import bcrypt from 'bcryptjs';
import { format } from 'date-fns';

export async function hashPassword(password: string): Promise<string> {
  return await bcrypt.hash(password, 10);
}

export async function verifyPassword(password: string, hash: string): Promise<boolean> {
  return await bcrypt.compare(password, hash);
}

export function generateToken(length: number = 32): string {
  return Array.from({ length: length }, () => 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789'.charAt(Math.floor(Math.random() * 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789'.length))).join('');
}

export function generateOrderNumber(): string {
  return `ORD-${format(new Date(), 'YYYYMMDDHHmmss')}-${Array.from({ length: 4 }, () => '0123456789'.charAt(Math.floor(Math.random() * '0123456789'.length))).join('')}`;
}

export function generateTransactionId(): string {
  return `TXN-${format(new Date(), 'YYYYMMDDHHmmss')}-${Array.from({ length: 8 }, () => 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789'.charAt(Math.floor(Math.random() * 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789'.length))).join('')}`;
}

export function generateTrackingNumber(): string {
  return `TRACK-${format(new Date(), 'YYYYMMDD')}-${Array.from({ length: 10 }, () => 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789'.charAt(Math.floor(Math.random() * 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789'.length))).join('').toUpperCase()}`;
}
